mapper.insert:
INSERT INTO inventory_check (
    check_no, status, remark, created_by
) VALUES (
    #{checkNo}, #{status}, #{remark}, #{createdBy}
)

mapper.select:
SELECT ic.id, ic.check_no, ic.status, ic.remark, ic.created_by, cu.real_name AS created_by_name, ic.executed_by, eu.real_name AS executed_by_name, ic.created_at, ic.executed_at FROM inventory_check ic LEFT JOIN sys_user cu ON ic.created_by = cu.id LEFT JOIN sys_user eu ON ic.executed_by = eu.id
AND ic.status = #{status}
ORDER BY ic.created_at DESC, ic.id DESC
